import mongoose from 'mongoose';
import dotenv from 'dotenv';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
dotenv.config({ path: path.resolve(__dirname, '../.env.local') });
dotenv.config({ path: path.resolve(__dirname, '../.env') });

const MONGO_URI = process.env.MONGO_URI;
if (!MONGO_URI) { console.error('MONGO_URI not found'); process.exit(1); }

const examCategorySchema = new mongoose.Schema({
  name: { type: String, required: true, trim: true },
  type: { type: String, enum: ['Central', 'State'], required: true },
  description: { type: String, trim: true }
}, { timestamps: true });

const examSchema = new mongoose.Schema({
  category: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamCategory', required: true },
  name: { type: String, required: true, trim: true },
  code: { type: String, required: true, uppercase: true, trim: true },
  description: { type: String, trim: true },
  isActive: { type: Boolean, default: true },
  logo: { type: String }
}, { timestamps: true });

const examPatternSchema = new mongoose.Schema({
  exam: { type: mongoose.Schema.Types.ObjectId, ref: 'Exam', required: true },
  title: { type: String, required: true, trim: true },
  duration: { type: Number, required: true, min: 1 },
  totalMarks: { type: Number, required: true, min: 0 },
  negativeMarking: { type: Number, default: 0, min: 0 },
  sections: [{
    name: { type: String, required: true, trim: true },
    totalQuestions: { type: Number, required: true, min: 1 },
    marksPerQuestion: { type: Number, required: true, min: 0 },
    negativePerQuestion: { type: Number, default: 0, min: 0 },
    sectionDuration: { type: Number, min: 0 }
  }]
}, { timestamps: true });

const practiceTestSchema = new mongoose.Schema({
  examPattern: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamPattern', required: true },
  title: { type: String, required: true, trim: true },
  slug: { type: String, lowercase: true, trim: true },
  totalMarks: { type: Number, required: true, min: 0 },
  duration: { type: Number, required: true, min: 1 },
  accessLevel: { type: String, enum: ['FREE', 'PRO'], default: 'FREE' },
  isPYQ: { type: Boolean, default: false },
  pyqYear: { type: Number, default: null },
  pyqShift: { type: String, default: null, trim: true },
  pyqExamName: { type: String, default: null, trim: true },
  publishedAt: { type: Date, default: Date.now },
  questions: [{
    questionText: { type: String, required: true },
    questionImage: { type: String, default: '' },
    options: [{ type: String, required: true }],
    optionImages: [{ type: String, default: '' }],
    correctAnswerIndex: { type: Number, required: true, min: 0 },
    explanation: { type: String, trim: true },
    section: { type: String, required: true, trim: true },
    tags: [{ type: String, trim: true }],
    difficulty: { type: String, enum: ['easy', 'medium', 'hard', 'mixed'], default: 'medium' }
  }]
}, { timestamps: true });

const ExamCategory = mongoose.models.ExamCategory || mongoose.model('ExamCategory', examCategorySchema);
const Exam = mongoose.models.Exam || mongoose.model('Exam', examSchema);
const ExamPattern = mongoose.models.ExamPattern || mongoose.model('ExamPattern', examPatternSchema);
const PracticeTest = mongoose.models.PracticeTest || mongoose.model('PracticeTest', practiceTestSchema);

const REA = 'General Intelligence';
const ENG = 'English Language';
const QA  = 'Quantitative Aptitude';
const GA  = 'General Awareness';

const KEY = [2, 3, 3, 3, 1, 1, 2, 2, 3, 2, 4, 1, 4, 4, 1, 4, 3, 4, 1, 4, 2, 3, 1, 1, 2, 2, 2, 2, 1, 2, 2, 1, 2, 1, 2, 2, 2, 2, 1, 2, 2, 1, 2, 3, 2, 2, 1, 1, 2, 3, 3, 3, 3, 2, 2, 1, 3, 2, 3, 2, 3, 3, 2, 3, 2, 3, 1, 1, 3, 2, 4, 2, 4, 3, 4, 1, 2, 4, 3, 3, 3, 2, 3, 4, 3, 1, 4, 1, 2, 3, 1, 3, 2, 1, 4, 1, 2, 3, 2, 2];
if (KEY.length !== 100) { console.error(`KEY length ${KEY.length}`); process.exit(1); }

const RAW = [
  { s: `General Intelligence`, q: `Aman walks 15 m east, then turns left and walks 10 m, then turns left again and walks 15 m. In which direction is he facing?`, o: [`East`, `West`, `North`, `South`], e: `From the given information path diagram will be. So, he is facing now in west direction. Thus, correct option is (b). Post LENGTH Selection 27, 2026, 28, 2026, Post 14:11:33 03:25:12` },
  { s: `General Intelligence`, q: `You see a colleag(Mueatcrhiceualatitniogni)n an exam. What should you do?`, o: [`Ignore and focusSoimn iylaoruPrappaeprer`, `Help the colleagu(eHeld on 30`, `Inform the invigilaJutol r2p02ri5vaSt1e)ly`, `Publicly accuse the colleague`], e: `Given: You see a (cHoellledagoune3c0heating in an exam. Explanation: Jul 2025 S1) Cheating undermines fairness and integrity. The most responsible action is to inform the invigilator privately, which addresses the issue appropriately without creating unnecessary disruption or public embarrassment. So, Inform the invigilator privately should you do. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `In the English alphabet, which letter is 7th from the left?`, o: [`E`, `F`, `G`, `H`], e: `Let's count from the left in the English alphabet: 1 - A, 2 - B, 3 - C, 4 - D, 5 - E, 6 - F, 7 - G So, G letter is 7th from the left. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `You find a mobile phone lying unattended in a public place. What should you do?`, o: [`Keep it for yourself`, `Ignore it`, `Submit it to the nearest police station or lost-and-found`, `Sell it`], e: `Given: You find a mobile phone lying unattended in a public place. Explanation: This is the most ethical and responsible action, as it helps return the lost item to its rightful owner safely. So, Submit it to the nearest police station or lost-and-found should you do. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `/yyyy --:-- --	Search	Clear (Held on 30 (Held on 30 Aman walks 15 m east, then turns left and walks 10 m, then turns left again and walks 15 m.`, o: [`I`, `J`, `K`, `H`], e: `Given: P : M :: L : ? Logic: Letters are decreasing - 3 place. For, P : M P-3=M Similarly, L:? L-3=I Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `/yyyy --:-- --	Search	Clear (Held on 30 (Held on 30 Aman walks 15 m east, then turns left and walks 10 m, then turns left again and walks 15 m.`, o: [`I`, `J`, `K`, `H`], e: `Given: A : D :: F : ? Logic: Letters are increasing + 3 place. For, A : D A+3=D Similarly, F:? F+3=I Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Book is to Reading as Food is to:`, o: [`Cooking`, `Eating`, `Taste`, `Hunger`], e: `Given: Book is to Reading as Food is to: A book is used for reading. Similarly, Food is used for eating. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `81 : 9 :: 49 : ?`, o: [`6`, `7`, `8`, `9`], e: `Given: 81 : 9 :: 49 : ? Logic: 1stnumber = 2nd number For, 81 : 9 81 = 9 Similarly, 49 : ? 49 = 7 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If \`#' means double the number, what is the value of 7 # ?`, o: [`12`, `13`, `14`, `15`], e: `Given: If \`#' means double the number. =7# =2×7 = 14 So, 14 is the value of 7 #. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `If A $ B = A² - B², find the value of 9 $ 5.`, o: [`36`, `56`, `64`, `81`], e: `Given: (A $ B = A2- B2) Expression: 9 $ 5 = 92- 52 = 81 - 25 = 56 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `What will come in the place of \`?' in the following equation, if \`+' and \`×' are interchanged and \`-' and \`÷' are interchanged? 12 + 24 - 6 × 3 ÷ 2 = ?`, o: [`47`, `48`, `50`, `49`], e: `Given: 12 + 24 - 6 × 3 ÷ 2 = ? Given Sign + - Interchanged Sign×÷ Using BODMAS rule. Operation preference wise Symbol Brackets [], , () Orders, of (power), (root), of Division ÷ Multiplication × Addition + Subtraction - New equation: 12 × 24 ÷ 6 + 3 - 2 = ? 12 × 4 + 3 - 2 = ? 48 + 3 - 2 = ? 51 - 2 = ? ? = 49 Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `What should come next in the series? EGI, FHJ, GIK, ?`, o: [`HJL`, `HJM`, `IJL`, `HJK`], e: `Given: EGI, FHJ, GIK, ? Logic: Letters are increasing + 1 place. E + 1 = F, F + 1 = G, G + 1 = H G + 1 = H, H + 1 = I, I + 1 = J I + 1 = J, J + 1 = K, K + 1 = L So, the missing term is HJL. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If "+" means division, "-" means multiplication, and "×" means addition, then which of the following is TRUE?`, o: [`only A`, `only B`, `A and C`, `B and C`], e: `Given: A. 8 + 2 = 5 B. 6 - 3 = 18 C. 5 × 4 = 9 Given Sign+ - × New Sign ÷×+ Using BODMAS rule. Symbol [], , () Operation preference wise Brackets (power), (root), of Orders, of ÷ Division × + Multiplication - Addition Subtraction A. 8 + 2 = 4 New equation: 8 ÷ 2 = 5 4 = 5 B. 6 - 3 = 18 New equation: 6 × 3 = 18 18 = 18 C. 5 × 4 = 9 New equation: 5 + 4 = 9 9=9 So, B and C is TRUE. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Identify the outlier.`, o: [`5`, `9`, `13`, `16`], e: `5, 9 and 13 are odd numbers. 16 is an even number. So, 16 is outlier. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Hunger : Food :: Thirst : ?`, o: [`Water`, `Sleep`, `Air`, `Heat`], e: `Given: Hunger : Food :: Thirst : ? Hunger is satisfied by food. Similarly, Thirst : ? Thirst is satisfied by water. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Identify the odd one out.`, o: [`Copper`, `Iron`, `Gold`, `Plastic`], e: `Copper, Iron and Gold are metals. Plastic is a non-metal. So, Plastic is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Key is to Lock as Password is to:`, o: [`Computer`, `Security`, `Login`, `Internet`], e: `Given: Key is to Lock as Password is to: A key is used to open a lock. Similarly, A password is used to access a login. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Identify the odd one out.`, o: [`Apple`, `Mango`, `Banana`, `Carrot`], e: `Apple, Mango and Banana are fruits. Carrot is a vegetable. So, Carrot is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Find the missing number: 5, 11, 23, 47, ___`, o: [`95`, `96`, `97`, `99`], e: `Given: 5, 11, 23, 47, __ Logic: Numbers are multiply by 2 and + 1. 5 × 2 + 1 = 11 11 × 2 + 1 = 23 23 × 2 + 1 = 47 47 × 2 + 1 = 95 So, the missing term is 95. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Find the number that is different: 4, 9, 16, 25, 35`, o: [`9`, `16`, `25`, `35`], e: `Given: 4, 9, 16, 25, 35 4 = 22 9 = 32 16 = 42 25 = 52 These are perfect squares, while 35 is not. So, 35 number that is different. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Identify the missing sequence: BDF, DFH, FHJ, ?, JLN`, o: [`EJL`, `HJL`, `HIJ`, `EJM`], e: `Given: BDF, DFH, FHJ, ?, JLN Logic: Letters are increasing + 2 place. B + 2 = D, D + 2 = F, F + 2 = H, H + 2 = J D + 2 = F, F + 2 = H, H + 2 = J, J + 2 = L F + 2 = H, H + 2 = J, J + 2 = L, L + 2 = N So, the missing term is HJL. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `What comes next: 2, 6, 14, 30, ?`, o: [`46`, `60`, `62`, `64`], e: `Given: 2, 6, 14, 30, ? Logic: Numbers are multiply by 2 and + 2. 2×2+2=6 6 × 2 + 2 = 14 14 × 2 + 2 = 30 30 × 2 + 2 = 62 So, the missing term is 62. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Brave : Courage :: Honest : ?`, o: [`Truthful`, `Careless`, `Proud`, `Silent`], e: `Given: Brave : Courage :: Honest : ? Brave is associated with courage. Similarly, Honest : ? Honest is associated with being truthful. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `In the English alphabet, find the position of M from the right.`, o: [`14`, `13`, `12`, `15`], e: `There are 26 letters in the English alphabet. The position of M from the left is 13. Position from the right: = 26 - 13 + 1 = 14 So, 14 is the position of M from the right. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If A is the wife of B and C is the father of B, how is A related to C?`, o: [`Daughter`, `Daughter-in-law`, `Sister`, `Wife`], e: `Given: If A is the wife of B and C is the father of B. From the given information blood relation diagram will be. So, A is the daughter-in-lawof C. Thus, correct option is (b).` },
  { s: `General Awareness`, q: `Which principle explains the floating of ships on water?`, o: [`Newton's First Law`, `Archimedes' Principle`, `Law of Gravitation`, `Boyle's Law`], e: `The correct answer is (B) Archimedes' Principle Explanation: · Archimedes' principle states that any object, totally or partially immersed in a fluid or liquid, is buoyed up by a force equal to the weight of the fluid displaced by the object. · A ship floats because it is designed to displace a weight of water equal to its own weight. Information Booster: · Buoyancy is the upward force exerted by a fluid that opposes the weight of a partially or fully immersed object. Additional Knowledge: · Newton's First Law (Option A): Relates to inertia. · Law of Gravitation (Option C): Explains the attraction between masses. · Boyle's Law (Option D): Relates to gas pressure and volume.` },
  { s: `General Awareness`, q: `The Sahitya Akademi Award is given for excellence in which field?`, o: [`Sports`, `Literature`, `Cinema`, `Science`], e: `The correct answer is (B) Literature Explanation: · The Sahitya Akademi Award is a literary honor in India, which the Sahitya Akademi annually confers on writers of the most outstanding books of literary merit. · It covers works in 24 major Indian languages. Information Booster: · It is the second-highest literary honor in India, after the Jnanpith Award. Additional Knowledge: · Khel Ratna (Option A): Sports excellence. · Dadasaheb Phalke Award (Option C): Cinema excellence. · Shanti Swarup Bhatnagar Prize (Option D): Science and Technology.` },
  { s: `General Awareness`, q: `The Asian Olympic Council organizes which major sporting event?`, o: [`Commonwealth Games`, `Asian Games`, `Olympics`, `Youth Olympics`], e: `The correct answer is (B) Asian Games Explanation: · The Olympic Council of Asia (OCA) is the governing body of sports in Asia. · It organizes the Asian Games every four years. Information Booster: · The first Asian Games were held in New Delhi, India, in 1951. Additional Knowledge: · Commonwealth Games (Option A): Organised by the Commonwealth Games Federation. · Olympics (Option C): Organised by the International Olympic Committee (IOC).` },
  { s: `General Awareness`, q: `______ wrote the famous book "India After Gandhi".`, o: [`Ramachandra Guha`, `Shashi Tharoor`, `Amartya Sen`, `Chetan Bhagat`], e: `The correct answer is (A) Ramachandra Guha Explanation: · 'India After Gandhi: The History of the World's Largest Democracy' is an acclaimed history book by Ramachandra Guha. · It covers the history of India from 1947 to the present day. Information Booster: · Ramachandra Guha is a renowned Indian historian and writer whose research interests include environmental, social, and political history. Additional Knowledge: · Shashi Tharoor (Option B): Wrote 'An Era of Darkness'. · Amartya Sen (Option C): Wrote 'The Argumentative Indian'.` },
  { s: `General Awareness`, q: `Which school of art developed mainly during the Gupta period?`, o: [`Gandhara`, `Mathura`, `Mughal`, `Rajput`], e: `The correct answer is (B) Mathura Explanation: · While the Mathura school began during the Kushana period, it reached its zenith during the Gupta period. · The Gupta period is often called the 'Golden Age' of Indian art. Information Booster: · Sarnath and Mathura were the two main centers of Gupta sculpture. Additional Knowledge: · Gandhara Art (Option A): Influenced by Greek and Roman styles. · Mughal School (Option C): Developed during the medieval period under Mughal Emperors.` },
  { s: `General Awareness`, q: `The Lavani dance form belongs to which Indian state?`, o: [`Gujarat`, `Maharashtra`, `Karnataka`, `Tamil Nadu`], e: `The correct answer is (B) Maharashtra Explanation: · Lavani is a combination of traditional song and dance, which is particularly performed to the beats of Dholki. · It is a popular folk dance of Maharashtra. Information Booster: · It is performed by female performers wearing nine-yard long sarees (Nauvari). Additional Knowledge: · Garba (Option A): Gujarat. · Yakshagana (Option C): Karnataka. · Bharatanatyam (Option D): Tamil Nadu (Classical).` },
  { s: `General Awareness`, q: `According to the 2011 Census, which state recorded the highest population density in India?`, o: [`Bihar`, `West Bengal`, `Uttar Pradesh`, `Kerala`], e: `The correct answer is (A) Bihar Explanation: · Population density is the number of persons per square kilometer. · Bihar is the most densely populated state with 1,106 persons per sq km. Information Booster: · West Bengal follows Bihar with a density of 1,028 persons per sq km. Additional Knowledge: · Uttar Pradesh (Option C): The most populous state in India. · Arunachal Pradesh: The state with the lowest population density.` },
  { s: `General Awareness`, q: `Which subject is included in the State List of the Indian Constitution?`, o: [`Defense`, `Police`, `Foreign Affairs`, `Currency`], e: `The correct answer is (B) Police Explanation: · The Seventh Schedule of the Indian Constitution divides powers between the Union and the States. · 'Police' and 'Public Order' are subjects under the State List. Information Booster: · Currently, the State List contains 61 subjects (originally 66). Additional Knowledge: · Defense, Foreign Affairs, and Currency (Options A, C, D): These are subjects under the Union List.` },
  { s: `General Awareness`, q: `Which Union Territory has the highest literacy rate in India (Census 2011)?`, o: [`Lakshadweep`, `Chandigarh`, `Delhi`, `Puducherry`], e: `The correct answer is (A) Lakshadweep Explanation: · According to the 2011 Census, Lakshadweep had a literacy rate of 91.85%. · It is the most literate Union Territory in India. Information Booster: · Among all States and UTs, Kerala has the highest literacy rate overall. Additional Knowledge: · Delhi (Option C): Literacy rate was 86.21%. · Chandigarh (Option B): Literacy rate was 86.05%.` },
  { s: `General Awareness`, q: `The Rowlatt Act of 1919 was introduced during the viceroyalty of:`, o: [`Lord Curzon`, `Lord Chelmsford`, `Lord Ripon`, `Lord Hardinge`], e: `The correct answer is (B) Lord Chelmsford Explanation: · Lord Chelmsford served as the Viceroy of India from 1916 to 1921. · The Rowlatt Act, which gave the government emergency powers to quell public unrest, was passed in March 1919. Information Booster: · This act led to the Jallianwala Bagh massacre on April 13, 1919. Additional Knowledge: · Lord Curzon (Option A): Known for the Partition of Bengal in 1905. · Lord Ripon (Option C): Known as the 'Father of Local Self-Government' in India.` },
  { s: `General Awareness`, q: `The Vernacular Press Act (1878) was introduced by which Viceroy?`, o: [`Lord Ripon`, `Lord Lytton`, `Lord Curzon`, `Lord Dalhousie`], e: `The correct answer is (B) Lord Lytton Explanation: · Lord Lytton introduced the Vernacular Press Act to curtail the freedom of the Indian-language (vernacular) press. · It was nicknamed the 'Gagging Act'. Information Booster: · Lord Ripon repealed this act in 1882. Additional Knowledge: · Lord Dalhousie (Option D): Famous for the Doctrine of Lapse and the introduction of Railways in India.` },
  { s: `General Awareness`, q: `Fill in the blank: The Right to Information Act, 2005 ensures transparency by providing citizens access to ______ held by public authorities.`, o: [`Private contracts`, `Government information`, `Personal bank records`, `Foreign policies`], e: `The correct answer is (B) Government information Explanation: · The RTI Act, 2005 empowers citizens to request information from a "public authority" (a body of Government or its instrumentalities). · It aims to promote transparency and accountability in the working of every public authority. Information Booster: · Information includes records, documents, memos, e-mails, opinions, and advice in any electronic or physical form. Additional Knowledge: · Option A & C: These are generally exempt from disclosure unless there is a larger public interest involved.` },
  { s: `General Awareness`, q: `Fill in the blank: The Ayushman Bharat scheme aims to provide ______ coverage to economically vulnerable families.`, o: [`Pension`, `Health insurance`, `Education loans`, `Housing subsidy`], e: `The correct answer is (B) Health insurance Explanation: · Ayushman Bharat Pradhan Mantri Jan Arogya Yojana (PM-JAY) provides a health cover of 5 lakhs per family per year. · It targets more than 12 crore poor and vulnerable families. Information Booster: · It is the world's largest government-funded healthcare program. Additional Knowledge: · Atal Pension Yojana (Option A): Relates to pensions for the unorganized sector. · PM Awas Yojana (Option D): Relates to housing subsidies.` },
  { s: `General Awareness`, q: `Fill in the blank: The document that outlines the government's estimated revenues and expenditures for a financial year is called the ______.`, o: [`Budget`, `Economic Survey`, `Fiscal Deficit`, `Revenue Bill`], e: `The correct answer is (A) Budget Explanation: · In India, the Budget is formally known as the Annual Financial Statement under Article 112. · It is a statement of the estimated receipts and expenditure of the Government of India for that particular year. Information Booster: · The Indian financial year runs from 1st April to 31st March. Additional Knowledge: · Economic Survey (Option B): A document presented by the Ministry of Finance reviewing the developments in the Indian economy over the past financial year.` },
  { s: `General Awareness`, q: `Fill in the blank: The Human Development Index (HDI) is based on health, education, and ______.`, o: [`Industrial growth`, `Income level`, `Agricultural output`, `Trade balance`], e: `The correct answer is (B) Income level Explanation: · The HDI is a composite index used by the UNDP to rank countries by level of human development. · It uses three dimensions: Long and healthy life, Knowledge (education), and a Decent standard of living (GNI per capita/income). Information Booster: · Mahbub ul Haq and Amartya Sen were instrumental in developing the HDI concept. Additional Knowledge: · Option A, C & D: These are economic indicators but not direct primary components of the HDI.` },
  { s: `General Awareness`, q: `What are "Kal Baisakhi" storms in India?`, o: [`Winter cyclones in northern India`, `Pre-monsoon thunderstorms in eastern India`, `Desert dust storms in Rajasthan`, `Monsoon depressions in the Bay of Bengal`], e: `The correct answer is (B) Pre-monsoon thunderstorms in eastern India Explanation: · Kal Baisakhi (Nor'westers) are local thunderstorms that occur in West Bengal and Assam during the summer season. · These are characterized by violent winds and heavy rainfall. Information Booster: · These storms are helpful for the cultivation of tea, jute, and rice. Additional Knowledge: · Loo (Option C): Hot and dry winds that blow in Northern India during summer.` },
  { s: `General Awareness`, q: `Fill in the blank: The Earth takes approximately ______ days to complete oCnoepyrerivgohltu©tio2n0a2r6oAundddat2h4e7Sun.`, o: [`365`, `300`, `360`, `400`], e: `The correct answer is (A) 365 Explanation: · Earth's revolution is the movement of the Earth around the Sun in a fixed path or orbit. · It takes approximately 365.25 days to complete one revolution. Information Booster: · The extra 0.25 day (6 hours) is added up every four years to form a leap year of 366 days. Additional Knowledge: · Rotation: The spinning of the Earth on its axis, which takes 24 hours.` },
  { s: `General Awareness`, q: `Which recent ISRO mission aims to study the Sun's corona and solar winds?`, o: [`Chandrayaan-3`, `Aditya-L1`, `Gaganyaan`, `Astrosat`], e: `The correct answer is (B) Aditya-L1 Explanation: · Aditya-L1 is the first Indian space mission to study the Sun. · It is placed in a halo orbit around the Lagrange point 1 (L1) of the Sun-Earth system. Information Booster: · The mission carries seven payloads to observe the photosphere, chromosphere, and the outermost layers of the Sun (the corona). Additional Knowledge: · Chandrayaan-3 (Option A): India's lunar landing mission. · Gaganyaan (Option C): India's upcoming manned space mission. · Astrosat (Option D): India's first dedicated multi-wavelength space observatory.` },
  { s: `General Awareness`, q: `What is the standard duration of a football match (excluding extra time)?`, o: [`60 minutes`, `70 minutes`, `90 minutes`, `120 minutes`], e: `The correct answer is (C) 90 minutes Explanation: · A standard association football match consists of two halves of 45 minutes each. · This results in a total of 90 minutes of regulation play. Information Booster: · There is usually a 15-minute half-time interval between the two halves. Additional Knowledge: · 120 minutes (Option D): The total duration if extra time (two halves of 15 minutes) is played to decide a winner.` },
  { s: `General Awareness`, q: `Which BRICS country is the largest by land area?`, o: [`Brazil`, `Russia`, `India`, `China`], e: `The correct answer is (B) Russia Explanation: · Russia is the largest country in the world by land area, covering over 17 million square kilometers. · It is a founding member of the BRICS group. Information Booster: · BRICS originally stood for Brazil, Russia, India, China, and South Africa. Additional Knowledge: · China (Option D): Second largest among BRICS by area. · Brazil (Option A): Third largest among BRICS by area.` },
  { s: `General Awareness`, q: `The Gwadar Port is located in which country?`, o: [`Iran`, `Pakistan`, `Oman`, `UAE`], e: `The correct answer is (B) Pakistan Explanation: · Gwadar is a strategic deep-water seaport located on the Arabian Sea in Balochistan province of Pakistan. · It is a key node in the China-Pakistan Economic Corridor (CPEC). Information Booster: · It is situated at the apex of the Arabian Sea and at the mouth of the Persian Gulf. Additional Knowledge: · Chabahar Port (Option A): A strategic port in Iran being developed by India.` },
  { s: `General Awareness`, q: `Which Indian site is a UNESCO World Heritage Site associated with Mughal architecture?`, o: [`Taj Mahal`, `Qutub Minar`, `Red Fort`, `Fatehpur Sikri`], e: `The correct answer is (A) Taj Mahal Explanation: · The Taj Mahal is considered the finest example of Mughal architecture, a style that combines elements from Persian, Indian, and Islamic architectural styles. · It was designated a UNESCO World Heritage Site in 1983. Information Booster: · It was built by Mughal Emperor Shah Jahan in memory of his wife Mumtaz Mahal. Additional Knowledge: · Qutub Minar (Option B): Built during the Delhi Sultanate period. · While C and D are also Mughal, the Taj Mahal is the most iconic representation.` },
  { s: `General Awareness`, q: `Which of the following is an example of a Ramsar Wetland Site in India?`, o: [`Keoladeo National Park`, `Jim Corbett National Park`, `Kaziranga National Park`, `Gir National Park`], e: `The correct answer is (A) Keoladeo National Park Explanation: · Keoladeo National Park (formerly Bharatpur Bird Sanctuary) in Rajasthan is a designated Ramsar site. · It is a man-made and man-managed wetland. Information Booster: · The Ramsar Convention is an international treaty for the conservation and sustainable use of wetlands. Additional Knowledge: · Jim Corbett (Option B): Famous for Tigers (Uttarakhand). · Kaziranga (Option C): Famous for One-horned Rhinos (Assam). · Gir (Option D): Famous for Asiatic Lions (Gujarat).` },
  { s: `General Awareness`, q: `In 2024, the National Commission for Women (NCW) continued its role in safeguarding women's rights. Which of the following is correct regarding its responsibilities?`, o: [`Conducting national elections`, `Reviewing constitutional and legal safeguards for women`, `Controlling monetary policy`, `Managing the Union Budget`], e: `The correct answer is (B) Reviewing constitutional and legal safeguards for women Explanation: · The NCW is a statutory body established under the National Commission for Women Act, 1990. · Its mandate includes reviewing constitutional and legal safeguards for women and recommending remedial legislative measures. Information Booster: · It also facilitates the redressal of grievances and advises the Government on all policy matters affecting women. Additional Knowledge: · Option A: Responsibility of the Election Commission of India. · Option C: Responsibility of the Reserve Bank of India (RBI). · Option D: Responsibility of the Ministry of Finance.` },
  { s: `General Awareness`, q: `Who has the power to appoint the Advocate General of a State in India?`, o: [`President of India`, `Chief Justice of India`, `Governor of the State`, `Prime Minister`], e: `The correct answer is (C) Governor of the State Explanation: · Article 165 of the Indian Constitution provides for the Advocate General for the States. · He/She is appointed by the Governor of the State and holds office during the pleasure of the Governor. Information Booster: · The Advocate General is the highest law officer in the state. Additional Knowledge: · President of India (Option A): Appoints the Attorney General of India. · Chief Justice of India (Option B): Head of the Judiciary. · Prime Minister (Option D): Head of the Union Council of Ministers.` },
  { s: `Quantitative Aptitude`, q: `Which of the following is not an integer?`, o: [`(3³ − 3)/3`, `√49`, `√2/2`, `(5² − 1)/2`], e: `A: (27−3)/3 = 8 ✓. B: √49 = 7 ✓. C: √2/2 is irrational, NOT an integer. D: (25−1)/2 = 12 ✓. Option C.` },
  { s: `Quantitative Aptitude`, q: `What is the value when 120 is increased by 25%?`, o: [`510`, `160`, `150`, `270`], e: `Given: Initial value = 120 Percentage increase = 25% Formula Used: New Value = Initial Value × (1 + P ercentage ) 100 Solution: Calculate the increase amount on 120: 25 Increase = 120 × = 30 100 Add the increase to the initial value: New value = 120 + 30 = 150 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `3 A rope is 15 meters long. It is cut into pieces each of 1.25 meters. How many full pieces can be cut, and how much rope will remain? 4`, o: [`12 pieces, 0.25 m left`, `13 pieces, 0.5 m left`, `12 pieces, 0.75 m left`, `13 pieces, 0.25 m left`], e: `Given: 3 Total length of the rope = 15 meters 4 Length of each cut piece = 1.25 meters Formula Used: Number of pieces = Total length ÷ Length of one piece Solution: Convert the mixed number to a decimal: 3 1 5 = 15.75 4 Calculate the number of pieces: 15.75 = 12.6 1.25 This means 12 full pieces can be cut. Calculate the total length used for 12 pieces: 12 × 1.25 = 15.00 Calculate the remaining length: 15.75 - 15.00 = 0.75 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `Which pair of number sets has the same elements?`, o: [`Natural numbers and integers`, `Whole numbers and natural numbers including 0`, `Rational numbers and real numbers`, `Complex numbers and real numbers`], e: `Given: Four pairs of number sets. Solution: Natural numbers contain elements starting from 1, 2, 3... Whole numbers contain elements starting from 0, 1, 2, 3... Therefore, the set of natural numbers including 0 is the exact definition of whole numbers. The sets Whole numbers and natural numbers including 0 have the exact same elements. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The average of 5 numbers is 62. Four of the numbers are 58, 65, 60, and 67. Find the missing number.`, o: [`49`, `60`, `35`, `67`], e: `Given: Average of 5 numbers = 62 Four of the numbers are 58, 65, 60, and 67 Formula Used: Sum = Average \\times Count Solution: Calculate the total sum of the 5 numbers: 62 × 5 = 310 Calculate the sum of the four given numbers: 58 + 65 + 60 + 67 = 250 Find the missing number by subtracting the sum of the four numbers from the total sum: 310 - 250 = 60 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A shopkeeper makes a 25% profit by selling a shirt for 750. What is the cost price?`, o: [`600`, `650`, `700`, `720`], e: `Given: Selling Price (SP) = 750 Profit Percentage = 25% Formula Used: Cost Price (CP) = SP × 100 100 + P rof it% Solution: Substitute the given values into the formula: CP = 750 × 100 100 + 25 = 750 × 100 125 = 6 × 100 = 600 The cost price is 600. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `15 men can complete a work in 12 days. After working for 6 days, 5 more men join them. In how many days will the remaining work be completed?`, o: [`4 days`, `5 days`, `4.5 days`, `3 days`], e: `Given: 15 men can complete the work in 12 days. After 6 days, 5 more men join the workforce. Formula Used: Total Work = Men × Days Solution: Calculate the total work required: Total work = 15 × 12 = 180 man-days. Calculate the work done in the first 6 days by 15 men: Work done = 15 × 6 = 90 man-days. Calculate the remaining work: Remaining work = 180 - 90 = 90 man-days. Calculate the new number of men: New men count = 15 + 5 = 20 men. Calculate the time taken to complete the remaining work: 90 Time = = 4.5 days. 20 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A triangle has an area of 45 cm² and a base of 15 cm. What is its height?`, o: [`5 cm`, `6 cm`, `7 cm`, `4 cm`], e: `Given: Area of triangle = 45 cm² Base = 15 cm Formula Used: 1 Area = ×base ×height 2 Solution: Substitute the given values into the area formula: 45 = 1 × 15×height 2 90 = 15× height Divide to isolate height: 90 height = = 6 cm 15 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The present population of a city is 12000. The population is increased by 10% in first year, and it is decreased by 20% in next year and third year 15% of the people is increased. What will be the population after 3 years?`, o: [`15115`, `13144`, `12144`, `None of the above`], e: `Given: Initial population = 12000 First year change = +10% Second year change = -20% Third year change = +15% Formula Used: Final Population = Initial ×(1 ± R1 ) × (1 ± R2 ) × C(1op±yrigRh3t ©) 2026 Adda247 100 100 100 Solution: Apply the successive percentage changes to the initial population: 10 20 15 Population after 3 years = 12000 × (1 + ) × (1 - ) × (1 + ) 100 100 100 110 80 115 = 12000 × × × 100 100 100 = 12000 × 1.1 × 0.8 × 1.15 = 13200 × 0.8 × 1.15 = 10560 × 1.15 = 12144 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `Find the square root of 64009.`, o: [`254`, `253`, `255`, `300`], e: `Given: Number = 64009 Formula Used: Square root determination using estimation and units digit matching. Solution: We know that 2502= 62500. Since 64009 is slightly greater than 62500, its square root must be slightly greater than 250. The number 64009 ends in 9, so its square root must end in either 3 or 7. Let's test the option 253: 253 × 253= 64009 Thus, the square root of 64009 is 253. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The cost price of an article is 80% of its selling price. What is the profit or the loss as percent?`, o: [`50%`, `33%`, `25%`, `40%`], e: `Given: Cost Price (CP) = 80% of Selling Price (SP) Formula Used: Profit% = SP - CP × 100 CP Solution: From the given condition, express CP in terms of SP: 80 CP = × SP 100 Find the ratio of SP to CP: SP 100 5 = = CP 80 4 Let SP = 5 units and CP = 4 units. Calculate the profit: Profit = 5 - 4 = 1 unit. Calculate the profit percentage: 1 Profit% = 4 × 100 = 25% Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A person bought an article at a discount of 30% and sold it at 10% above the marked price. What is the profit percentage?`, o: [`40%`, `50%`, `57.14%`, `60%`], e: `Given: Discount on original Marked Price = 30% Selling Price = 10% above original Marked Price Formula Used: Profit % = SP - CP × 100 CP Solution: Let the initial marked price be 100 units. The person bought it at a 30% discount. Cost Price = 100 - 30 = 70 units. The person sold it at 10% above the marked price. Selling Price = 100 + 10 = 110 units. Calculate the profit made: Profit = 110 - 70 = 40 units. Calculate the profit percentage: 40 Profit% = ×100 70 400 Profit% = 57.14% 7 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A wooden block has dimensions 8 cm × 5 cm × 3 cm. What is its volume?`, o: [`167 cm³`, `120 cm³`, `230 cm³`, `478 cm³`], e: `Given: Dimensions of the block = 8 cm, 5 cm, and 3 cm Formula Used: Volume of a cuboid = length × width × height Solution: Substitute the given dimensions into the volume formula: Volume = 8 ×5 × 3 Volume = 40 × 3 = 120 cm³ Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `57 What is the sum of 3 + 4 written as a mixed number in simplest form? 8 12 4`, o: [`3`, `6`, `8`, `8`], e: `Given: 5 7 Two mixed numbers: 3 and 4 8 12 Solution: We can add the whole parts and fractional parts separately. 57 Sum = 3 + 4 + + 8 12 15 14 =7+ + 24 24 29 =7+ 24 Since the fraction is improper, we convert it to a mixed number: 29 5 =1 24 24 Add this back to the whole number part: 55 Total = 7 + 1 + = 8 24 24 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `The average of 8 consecutive numbers starting from 10 is:`, o: [`14`, `13.5`, `12`, `15`], e: `Given: 8 consecutive numbers starting from 10 Formula Used: Average of an arithmetic progression = F irstterm + LCaosptytreigrhmt © 2026 Adda247 2 Solution: The 8 consecutive numbers are 10, 11, 12, 13, 14, 15, 16, and 17. First term = 10 Last term = 17 Substitute these into the average formula: Average = 10 + 17 27 2 = = 13.5 2 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `An overhead water tank is made by placing a hemisphere over a cylinder. The cylinder has a height of 3 m, and the radius of both shapes is 2 m. What is the total volume of the tank in cubic meters? (Use = 3.14)`, o: [`87.43 m³`, `34.56 m³`, `54.43 m³`, `84.53 m³`], e: `Given: Height of cylinder (h) = 3 m Radius of cylinder and hemisphere (r) = 2 m Formula Used: Volume of cylinder = r2h Volume of hemisphere = 2r3 3 Solution: First, find the volume of the cylindrical part: Vcyl = 3.14 × 22 × 3 = 3.14 × 4 × 3= 37.68 m³ Next, find the volume of the hemispherical part: Vhemi = 2 × 3.14 × 23 = 2 × 3.14 × 8 = 50.24 = 16.746... m³ 3 3 3 Calculate the total volume of the tank: V = 37.68 + 16.746 = 54.426 m³ Rounding off to two decimal places, we get 54.43 m³. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A product has a marked price of 1,200. If a 20% discount is applied, what is the selling price?`, o: [`960`, `1,000`, `940`, `1,100`], e: `Given: Marked Price (MP) = 1200 Discount Percentage = 20% Formula Used: Selling Price (SP) = MP ×(1 - Discount% ) 100 Solution: Calculate the discount amount: 20 Discount = 1200 × = 240 100 Calculate the selling price by subtracting the discount from the marked price: SP = 1200 - 240 = 960 The selling price is 960. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A runner is jogging on a circular track with a circumference of 400 meters. If the runner maintains a constant speed of 8 km/h, how much time will it take to complete 5 laps around the track?`, o: [`15 minutes`, `55 minutes`, `67 minutes`, `20 minutes`], e: `Given: Circumference of track = 400 meters Speed = 8 km/h Number of laps = 5 Formula Used: Time = Distance Speed Solution: Calculate the total distance to be covered: Distance = 5 × 400= 2000 meters Convert the distance to kilometers: Distance = 2 km Calculate time using the formula: 2 Time = = 0.25 hours 8 Convert hours to minutes: 0.25 × 60 = 15 minutes Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `If 6 men can complete a work in 16 days, how many men are required to complete the same work in 12 days?`, o: [`13`, `6`, `8`, `4`], e: `Given: Men (M1) = 6 Days (D1) = 16 Target Days (D2) = 12 Formula Used: M1 × D1 = M2 × D2 Solution: Substitute the given values into the work equivalence formula: 6× 16 = M2 × 12 96 = M2× 12 96 M2 = = 8 12 Therefore, 8 men are required to complete the work in 12 days. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A chord of length 12 cm is 5 cm away from the center. Find the radius.`, o: [`7 cm`, `61cm`, `19/5 cm`, `10cm`], e: `Given: Length of chord = 12 cm Distance from center = 5 cm Formula Used: Radius2 = (Half of chord)2 + (Distance from center)2 Solution: A perpendicular drawn from the center of a circle to a chord bisects the chord. 12 Half of the chord = = 6 cm 2 Using the Pythagorean theorem in the formed right-angled triangle: r2 = 62 + 52 r2= 36 + 25 = 61 r = 61cm Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `If the ratio is 4 : 10 = x : 20. Then find the x.`, o: [`7`, `6`, `10`, `8`], e: `Given: Proportion: 4 : 10 = x : 20 Formula Used: ac = bd Solution: Write the given ratio as a fraction equation: 4x = 10 20 10 × x = 4 × 20 10x = 80 80 x= =8 10 Final Answer So the correct answer is (d)` },
  { s: `Quantitative Aptitude`, q: `A person lends 20,000 at 12% simple interest per annum. What will be the interest earned in 2.5 years?`, o: [`5,000`, `6,000`, `5,500`, `6,500`], e: `Given: Principal (P) = 20,000 Rate (R) = 12% per annum Time (T) = 2.5 years Formula Used: P ×R×T Simple Interest (SI) = 100 Solution: Substitute the given values into the Simple Interest formula: SI = 20000 × 12 × 2.5 100 = 200 × 12 × 2.5 = 200 × 30 = 6000 The interest earned is 6,000. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `If the volume of a right circular cone is 616 cm³ and height is 12 cm, what is the radius of the base?`, o: [`4 cm`, `5 cm`, `6 cm`, `7 cm`], e: `Given: Volume of cone = 616 cm³ Height (h) = 12 cm Formula Used: Volume of a cone = 1r2h 3 Solution: 22 Substitute the given values into the volume formula, using = : 7 6 16 = 1 × 22 × r2 × 12 37 616 = 22 × r2 × 4 7 616 = 88 × r2 7 r2 = 616 × 7 88 r2 = 7 × 7 = 49 r = 7cm Final Answer So the correct answer is (d)` },
  { s: `Quantitative Aptitude`, q: `A man walks at 4 km/h. After 6 hours, he is overtaken by a cyclist who started 2 hours after him. What is the speed of the cyclist?`, o: [`7 km/h`, `5 km/h`, `6 km/h`, `8 km/h`], e: `Given: Speed of man = 4 km/h Man walks for 6 hours. Cyclist starts 2 hours after the man and overtakes him at the 6-hour mark. Formula Used: Distance = Speed ×Time Speed = Distance T ime Solution: Calculate the total distance covered by the man in 6 hours: Distance = 4 × 6 = 24 km. The cyclist starts 2 hours late, which means the cyclist traveled for: Time = 6 - 2 = 4 hours. The cyclist covers the same 24 km distance in 4 hours. Calculate the speed of the cyclist: 24 Speed = = 6 km/h. 4 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `Shivangi bought two varieties of pulses, costing Rs. 50 per kg and Rs. 60 per kg each, and mixed them in some ratio. Then she sold the mixture at Rs. 70 per kg. Making a profit of 20 percent. What was the ratio of the mixture?`, o: [`1:6`, `2:3`, `2:5`, `1:5`], e: `Given: Cost Price of Variety 1 = Rs. 50/kg Cost Price of Variety 2 = Rs. 60/kg Selling Price of mixture = Rs. 70/kg Profit Percentage = 20% Formula Used: Cost Price = SellingP rice × 100 100 + P rof it% Solution: Calculate the mean Cost Price of the mixture: 70 × 100 700 175 CP = = = 120 12 3 Apply the rule of alligation with the two prices, 50 and 60: 175 180 - 175 5 Difference 1 = 60 - = = 3 3 3 175 - 50 = 175 - 150 25 Difference 2 = = 3 3 3 The ratio of Variety 1 to Variety 2 is: Ratio = 5 : 25 = 5 : 25 = 1 : 5 33 Final Answer So the correct answer is (d)` },
  { s: `English Language`, q: `Pick the correctly spelled word:`, o: [`Conscientious`, `Consientious`, `Consciencious`, `Conscientous`], e: `Option (A) is the correctly spelt word. The correct spelling is Conscientious, which means careful, diligent, and guided by a sense of duty. It is used for a person who performs work sincerely and with full responsibility. Hindi meaning: , , . Example: She is a conscientious student who completes every assignment on time. Meanings of all the given options: Option A: Conscientious = careful and responsible in doing work () Option B: Consientious = incorrect spelling of conscientious Option C: Consciencious = incorrect spelling of conscientious Option D: Conscientous = incorrect spelling of conscientious So the correct answer is (a).` },
  { s: `English Language`, q: `Which of the following words is spelled correctly?`, o: [`Embarassment`, `Embarrassment`, `Embarrasment`, `Embarrasssment`], e: `Option (B) is the correctly spelt word. The correct spelling is Embarrassment, which means a feeling of shame, awkwardness, or discomfort. It is generally used when a person feels uneasy due to a mistake or an uncomfortable situation. Hindi meaning: , , . Example: He felt deep embarrassment after forgetting the speaker's name on stage. Meanings of all the given options: Option A: Embarassment = incorrect spelling of embarrassment Option B: Embarrassment = a feeling of shame or awkwardness () Option C: Embarrasment = incorrect spelling of embarrassment Option D: Embarrasssment = incorrect spelling of embarrassment So the correct answer is (b).` },
  { s: `English Language`, q: `Choose the option that will replace the error highlighted in bold. Although she studied very hard, she managed to pass the examination.`, o: [`Unless`, `However`, `Despite`, `Because`], e: `The correct substitution of the highlighted word is (D) Because. The sentence shows a clear cause-and-result relationship. She studied very hard, and as a result, she managed to pass the examination. Therefore, because is the appropriate conjunction. The word although is used to show contrast, but there is no contrast in the sentence. The correct sentence will be: Because she studied very hard, she managed to pass the examination. Grammatical rule used: Because introduces reason or cause, whereas although introduces contrast or concession. Example: Because he worked sincerely, he succeeded. / Although he was tired, he continued working. Information booster: Despite is followed by a noun or gerund, not by a full clause directly. So Despite she studied very hard is incorrect. So the correct ` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: She has been teaching (1) / at this school (2) / since ten years (3) / with great dedication. (4)`, o: [`She has been teaching (1)`, `at this school (2)`, `since ten years (3)`, `with great dedication. (4)`], e: `Option (C) contains an error. The phrase since ten years is incorrect. With the Present Perfect Continuous Tense, since is used for a point of time, while for is used for a period or duration of time. Here, ten years shows a duration, so the correct expression is for ten years. The correct sentence will be: She has been teaching at this school for ten years with great dedication. Grammatical rule used: Use since with a specific starting point such as 2015, Monday, morning, childhood, etc. Use for with a duration such as two hours, five days, ten years, etc. Example: He has been living here since 2018. / He has been living here for five years. Information booster: In exam questions, the confusion between since and for is very common. Always check whether the time expression is a point of ti` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The children have been playing (1) / in this park (2) / since two hours (3) / without any break. (4)`, o: [`The children have been playing (1)`, `in this park (2)`, `since two hours (3)`, `without any break. (4)`], e: `Option (C) contains an error. The phrase since two hours is grammatically incorrect because two hours expresses duration, not a starting point. Therefore, for two hours should be used in the sentence. The correct sentence will be: The children have been playing in this park for two hours without any break. Grammatical rule used: Use for with a period of time and since with a point of time in perfect and perfect continuous tenses. Example: She has been waiting for three hours. / She has been waiting since 6 p.m. Information booster: Words like two hours, many years, a long time always take for, whereas words like Monday, 2010, morning, childhood take since. So the correct answer is (c).` },
  { s: `English Language`, q: `Choose the correct one-word substitution for: "A person who hates and distrusts everyone ___".`, o: [`Altruist`, `Egotist`, `Misanthrope`, `Narcissist`], e: `The correct option is (C) Misanthrope. A misanthrope is a person who dislikes, hates, or distrusts humankind in general. Such a person tends to avoid social interaction because of a negative view of people. Hindi meaning: . Example: The old man in the novel is portrayed as a misanthrope who prefers isolation. Meanings of the given other options: Option A: Altruist = a person who cares selflessly for others () Option B: Egotist = a self-centered person who thinks too much of oneself () Option D: Narcissist = a person excessively in love with oneself ( ) So the correct answer is (c).` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate collocation: The board took three hours to __ a decision on the proposal.`, o: [`do`, `reach`, `perform`, `conduct`], e: `The correct option to fill in the blank is (B) reach. The standard collocation is reach a decision, which means to arrive at a conclusion after discussion or consideration. Hindi meaning of reach in this context: . Example: After a long debate, the committee finally reached a decision. Explain why other options are incorrect: Option A: do is not used with decision in standard English. Option C: perform is used for tasks, duties, or functions, not with decision. Option D: conduct is used with activities like an inquiry, survey, or meeting, not with decision. So the correct answer is (b).` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate option: No sooner had he sat down at his desk __ the fire alarm went off.`, o: [`when`, `while`, `than`, `until`], e: `The correct option to fill in the blank is (C) than. The correlative conjunction used with No sooner is always than. This structure expresses that one action happened immediately after another. The correct sentence is: No sooner had he sat down at his desk than the fire alarm went off. Example: No sooner had she entered the room than everyone stood up. Explain why other options are incorrect: Option A: when is used with hardly/scarcely in some structures, not with no sooner. Option B: while shows simultaneous action, which is not intended here. Option D: until does not fit this immediate-sequence construction. Information booster: Remember the fixed pairs: No sooner...than and Hardly/Scarcely...when. So the correct answer is (c).` },
  { s: `English Language`, q: `Fill in the blank with the most appropriate tense: By the time the doctor arrived, the patient ___________ consciousness.`, o: [`loses`, `lost`, `will lose`, `had lost`], e: `The correct option to fill in the blank is (D) had lost. The sentence contains two actions in the past. The patient lost consciousness before the doctor arrived. When one past action happened before another past action, the earlier action is expressed in the Past Perfect Tense. Therefore, had lost is the correct tense form in this context. Example: By the time we reached the station, the train had left. Explain why other options are incorrect: Option A: loses is in the Present Simple Tense and does noCtofpityarigphatst©-ti2m0e26seAqdudean2c4e7. Option B: lost is Past Simple, but it does not clearly show that the action happened before the doctor's arrival. Option C: will lose is Future Tense and is contextually incorrect. Information booster: In sentences beginning with By the time + past ` },
  { s: `English Language`, q: `Choose the correct meaning of the given idiom/phrase from the options: "Burn the midnight oil"`, o: [`To waste valuable resources`, `To celebrate an achievement`, `To work or study very late into the night`, `To cause destruction deliberately`], e: `Option (C) is the correct meaning of the given idiom. Burn the midnight oil means to work or study till very late at night, especially with great effort. It usually refers to hard work done after normal working hours. Hindi meaning: . Example: She burned the midnight oil to finish her project before the deadline. Other related idioms and their meanings: Hit the books = to study seriously Pull an all-nighter = to stay awake all night for work or study Go the extra mile = to put in extra effort So the correct answer is (c).` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: A owl (1) / was perched silently (2) / on the old branch (3) / throughout the night. (4)`, o: [`A owl (1)`, `was perched silently (2)`, `on the old branch (3)`, `throughout the night. (4)`], e: `Option (A) contains an error. The phrase A owl is incorrect because the word owl begins with a vowel sound. Therefore, the correct article to be used before it is an, not a. The correct sentence will be: An owl was perched silently on the old branch throughout the night. Grammatical rule used: Use an before words beginning with a vowel sound, and use a before words beginning with a consonant sound. Example: An apple, an hour, a university, a European country. Information booster: Articles depend on sound, not merely on spelling. For example, hour takes an because the sound begins with a vowel, while university takes a because it begins with the consonant sound /y/. So the correct answer is (a).` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The children were playing (1) / in the garden (2) / when the storm (3) / suddenly blow. (4)`, o: [`The children were playing (1)`, `in the garden (2)`, `when the storm (3)`, `suddenly blow. (4)`], e: `Option (D) contains an error. The verb blow is incorrect in this sentence because the entire sentence is in the past. Therefore, the correct form should be blew. The sentence describes an action that happened while the children were playing. The correct sentence will be: The children were playing in the garden when the storm suddenly blew. Grammatical rule used: When the sentence refers to a completed event in the past, the verb should be in the Past Simple Tense. The past form of blow is blew. Example: We were walking home when a cold wind suddenly blew. Information booster: In narrative sentences, one action may be in Past Continuous and the interrupting action in Past Simple, as in was/were + verb- ing with another simple past verb. So the correct answer is (d).` },
  { s: `English Language`, q: `Arrange the passage logically: (1) He switched on his laptop. (2) He sat down at his desk. (3) He opened the email and began to reply. (4) An email notification popped up on the screen.`, o: [`2-1-4-3`, `1-2-4-3`, `2-4-1-3`, `1-4-2-3`], e: `Option A is the correct order of the given sentences. Explanation of the correct order: · Sentence (2) comes first because a person normally sits at the desk before beginning work. · Sentence (1) follows naturally, because after sitting downC,ohpeysriwgihtcth©ed20o2n6hAisdldaap2to4p7. · Sentence (4) comes next, as the email notification could appear only after the laptop was switched on. · Sentence (3) is the final action, because after seeing the notification, he opened the email and replied to it. This sequence is grammatically, logically, and contextually coherent. So the correct answer is (a).` },
  { s: `English Language`, q: `Choose the correct meaning of the given idiom/phrase from the options: "Bite the bullet":`, o: [`To act with reckless courage`, `To endure a painful situation bravely`, `To cause harm to others`, `To avoid a difficult decision`], e: `Option (B) is the correct meaning of the given idiom. Bite the bullet means to face a difficult, painful, or unpleasant situation with courage and patience instead of avoiding it. Hindi meaning: . Example: He decided to bite the bullet and accept the challenging transfer. Other related idioms and their meanings: Face the music = to accept the unpleasant consequences Keep your chin up = to remain cheerful in difficulty Take the bull by the horns = to deal with a problem boldly So the correct answer is (b).` },
  { s: `English Language`, q: `Choose the correct one-word substitution for: "A person who is new to and inexperienced in a particular activity ___".`, o: [`Veteran`, `Prodigy`, `Novice`, `Maestro`], e: `The correct option is (C) Novice. A novice is a beginner who has little or no experience in a particular field or activity. The word is used for someone who is just starting to learn. Hindi meaning: , . Example: As a novice in public speaking, she was initially nervous on stage. Meanings of the given other options: Option A: Veteran = an experienced person ( ) Option B: Prodigy = a person, especially a child, with exceptional talent ( ) Option D: Maestro = a master in music or any art (, ) So the correct answer is (c).` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) Allow the dough to rise for an hour. (2) Mix flour, yeast, water, and salt in a bowl. (3) Bake in a preheated oven for 30 minutes. (4) Knead the dough until it becomes smooth.`, o: [`2 ­ 4 ­ 1 ­ 3`, `4 ­ 2 ­ 1 ­ 3`, `2 ­ 1 ­ 4 ­ 3`, `1 ­ 2 ­ 4 ­ 3`], e: `Option A is the correct order of the given sentences. Explanation of the correct order: · Sentence (2) must come first because the ingredients need to be mixed before any further step can happen. · Sentence (4) follows, as kneading is done after mixing to prepare the dough properly. · Sentence (1) comes next, because after kneading, the dough is left to rise. · Sentence (3) is the final step, because baking can happen only after the dough has risen sufficiently. Thus, the sequence 2 ­ 4 ­ 1 ­ 3 forms a complete and logical process. So the correct answer is (a).` },
  { s: `English Language`, q: `Fill in the blank with the appropriate adverb. The surgeon performed the procedure _______ to avoid any complications.`, o: [`carelessly`, `hastily`, `meticulously`, `negligently`], e: `The correct option to fill in the blank is (C) meticulously. Meticulously means very carefully and with great attention to detail. In the context of a surgeon performing a procedure to avoid complications, this adverb fits both grammatically and contextually. Hindi meaning: , . Example: The architect meticulously checked every measurement before approval. Explain why other options are incorrect: Option A: carelessly means without care ( ), which is opposite to the required meaning. Option B: hastily means quickly and in a rushed manner ( ), which may increase complications. Option D: negligently means irresponsibly or without proper attention (), which is again unsuitable in the medical context. So the correct answer is (c).` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) The water began to boil. (2) She placed the pan on the stove. (3) She added pasta to the boiling water. (4) She filled the pan with water.`, o: [`2-4-1-3`, `4-2-1-3`, `4-1-2-3`, `2-1-4-3`], e: `Option B is the correct order of the given sentences. Explanation of the correct order: · Sentence (4) is the first step because the pan must be filled with water before it can be heated. · Sentence (2) comes next, as the filled pan is then placed on the stove. · Sentence (1) follows naturally because the water starts boiling after the pan is heated. · Sentence (3) is the final step, because pasta is added only after the water has begun to boil. Hence, 4-2-1-3 is the only logical and process-based arrangement. So the correct answer is (b).` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) The officer stamped the documents and handed them back. (2) He submitted the application form at the counter. (3) He took a token and waited for his turn. (4) He entered the government office and stood in the queue.`, o: [`4 ­ 3 ­ 2 ­ 1`, `3 ­ 4 ­ 2 ­ 1`, `4 ­ 2 ­ 3 ­ 1`, `2 ­ 4 ­ 3 ­ 1`], e: `Option A is the correct order of the given sentences. Explanation of the correct order: · Sentence (4) begins the sequence because entering the office is the first action. · Sentence (3) follows, as after entering, he took a token and waited for his turn. · Sentence (2) comes next because only when his turn arrived could he submit the application form. · Sentence (1) is the last step, where the officer processed the documents and returned them. Therefore, 4 ­ 3 ­ 2 ­ 1 is the most coherent order. So the correct answer is (a).` },
  { s: `English Language`, q: `Fill in the correct collocation in the following sentence. The government has decided to _____ a new policy on reCnoepwyaribglhete©ne2r0g2y6. Adda247`, o: [`do`, `make`, `perform`, `implement`], e: `The correct option to fill in the blank is (D) implement. The verb implement means to put a plan, system, or policy into effect. In the given sentence, the government has decided to bring a new policy into operation, so implement is the most suitable word. Hindi meaning: . Example: The administration implemented new safety rules across all departments. Explain why other options are incorrect: Option A: do is too general and is not used with policy in this sense. Option B: make may be used with plans or arrangements, but make a policy does not fit as well here as implement a policy. Option C: perform is used for duties, operations, or tasks, not for policy. So the correct answer is (d).` },
  { s: `English Language`, q: `Choose the word that is closest in meaning to 'Mendacious':`, o: [`Deceptive`, `Upright`, `Trustworthy`, `Reliable`], e: `The correct synonym of the given word is (A) Deceptive. Mendacious means dishonest or untruthful. It describes a person, statement, or behavior that is based on lies or falsehood. Hindi meaning: , . Example: The witness gave a mendacious statement before the court. Deceptive means misleading or giving a false impression. It is close in meaning to mendacious because both involve dishonesty and false representation. Hindi meaning: , . Example: The advertisement was deceptive and hid the real cost of the product. Synonyms: false, dishonest, deceitful, untruthful. Antonyms: honest, truthful, upright, reliable. Meanings of all the other given options: Option B: Upright = honest and morally correct (, ) Option C: Trustworthy = deserving trust or confidence () Option D: Reliable = dependable and ` },
  { s: `English Language`, q: `Arrange the following sentences to form a logical and cCoohpeyreringthstt©or2y:026 Adda247 (1) Seeing this, the teacher calmly restored order in the class. (2) The substitute teacher entered a noisy classroom. (3) Within minutes, the students settled and opened their books. (4) She introduced herself and asked everyone to take their seats.`, o: [`1-2-4-3`, `2-4-1-3`, `2-1-4-3`, `4-2-1-3`], e: `Option B is the correct order of the given sentences. Explanation of the correct order: · Sentence (2) introduces the setting: the substitute teacher entered a noisy classroom. · Sentence (4) logically follows because after entering, she introduced herself and instructed the students to sit down. · Sentence (1) comes next, where, seeing the disorder, she restored order calmly in the class. · Sentence (3) is the result of her action, as the students then settled and opened their books. Thus, 2-4-1-3 forms the most natural and coherent story. So the correct answer is (b).` },
  { s: `English Language`, q: `Explanation of the correct order: Sentence (2) introduces the setting: the substitute teacher entered a noisy classroom. Sentence (4) logically follows because after entering, she introduced herself and instructed the students to sit down. Sentence (1) comes next, where, seeing the disorder, she restored order calmly in the class. Sentence (3) is the result of her action, as the students then settled and opened their books. Thus, 2-4-1-3 forms the most natural and coherent story. So the correct answer is (b).`, o: [`Bleak`, `Fruitless`, `Bountiful`, `Parched`], e: `The correct antonym of the given word is (C) Bountiful. Barren means unproductive, infertile, or unable to produce growth. It may refer to land, ideas, or situations lacking results or richness. Hindi meaning: , . Example: The farmers could not grow crops on the barren land. Bountiful means abundant, plentiful, or rich in yield. It is the opposite of barren because it expresses productivity and abundance. Hindi meaning: , . Example: The region had a bountiful harvest this year. Synonyms of barren: infertile, sterile, dry, unproductive. Antonyms of barren: fertile, fruitful, bountiful, productive. Meanings of all the other given options: Option A: Bleak = cold, empty, or without hope (, ) Option B: Fruitless = unsuccessful or producing no result () Option D: Parched = extremely dry due to h` },
  { s: `English Language`, q: `Example: The region had a bountiful harvest this year. Synonyms of barren: infertile, sterile, dry, unproductive. Antonyms of barren: fertile, fruitful, bountiful, productive. Meanings of all the other given options: Option A: Bleak = cold, empty, or without hope (उजाड़, िनराशाजनक) Option B: Fruitless = unsuccessful or producing no result (िनष्फल) Option D: Parched = extremely dry due to heat (सूखा हुआ) So the correct answer is (c).`, o: [`Sombre`, `Lively`, `Brooding`, `Dull`], e: `The correct synonym of the given word is (B) Lively. Jovial means cheerful, happy, and full of friendliness. It is used for a person who has a pleasant and light-hearted nature. Hindi meaning: , . Example: Our jovial host made every guest feel comfortable at the gathering. Lively means full of life, energy, and enthusiasm. It matches the sense of cheerfulness and spirited nature conveyed by the word jovial. Hindi meaning: , . Example: She gave a lively response during the discussion. Synonyms: cheerful, merry, genial, buoyant. Antonyms: gloomy, dull, depressed, sombre. Meanings of all the other given options: Option A: Sombre = serious, dark, or gloomy in mood (, ) Option C: Brooding = deeply thoughtful in a sad or worried way (, ) Option D: Dull = boring, lacking brightness or interest (,` },
  { s: `English Language`, q: `Choose the word opposite in meaning to 'Insipid':`, o: [`Flat`, `Pungent`, `Colourless`, `Tedious`], e: `The correct antonym of the given word is (B) Pungent. Insipid means lacking flavor, interest, or vigor. It is used for food that is tasteless and also for speech or writing that is dull. Hindi meaning: , . Example: The soup was so insipid that nobody wanted a second serving. Pungent means having a strong, sharp taste or smell; figuratively, it may also mean forceful or striking. It is opposite in sense to insipid because it suggests strong flavor or vivid effect. Hindi meaning: , . Example: The pungent aroma of spices filled the kitchen. Synonyms of insipid: bland, dull, flat, tasteless. Antonyms of insipid: pungent, flavorful, vivid, stimulating. Meanings of all the other given options: Option A: Flat = lacking liveliness or flavor (, ) Option C: Colourless = dull or lacking interest ( , ` }
];

if (RAW.length !== 100) { console.error(`Expected 100 questions, got ${RAW.length}`); process.exit(1); }

async function seed() {
  console.log('Connecting to MongoDB...');
  await mongoose.connect(MONGO_URI);
  console.log('Connected.');

  let category = await ExamCategory.findOne({ name: 'Central', type: 'Central' });
  if (!category) {
    category = await ExamCategory.create({ name: 'Central', type: 'Central', description: 'Central government competitive exams' });
  }

  let exam = await Exam.findOne({ code: 'SSC-SSP-MAT' });
  if (!exam) {
    exam = await Exam.create({
      category: category._id,
      name: 'SSC Selection Post (Matriculation Level)',
      code: 'SSC-SSP-MAT',
      description: 'Staff Selection Commission - Selection Post (Matriculation Level)',
      isActive: true
    });
  }

  const PATTERN_TITLE = 'SSC Selection Post (Matriculation Level)';
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE, duration: 60, totalMarks: 200, negativeMarking: 0.5,
      sections: [
        { name: REA, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: GA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: QA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: ENG, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 }
      ]
    });
  }

  const TEST_TITLE = 'SSC Selection Post (Matriculation) - 30 July 2025 Shift-1 [Similar Paper]';
  await PracticeTest.deleteMany({ examPattern: pattern._id, title: TEST_TITLE });

  const questions = RAW.map((r, i) => ({
    questionText: r.q,
    questionImage: '',
    options: r.o,
    optionImages: ['', '', '', ''],
    correctAnswerIndex: KEY[i] - 1,
    explanation: r.e || '',
    section: r.s,
    tags: ['SSC', 'Selection Post', 'Phase XIII', 'Matriculation', 'PYQ', '2025', 'Similar Paper'],
    difficulty: 'medium'
  }));

  const test = await PracticeTest.create({
    examPattern: pattern._id, title: TEST_TITLE, totalMarks: 200, duration: 60,
    accessLevel: 'FREE', isPYQ: true, pyqYear: 2025, pyqShift: '1',
    pyqExamName: 'SSC Selection Post Phase XIII (Matriculation) - Similar Paper', questions
  });
  console.log(`Created PYQ PracticeTest: ${test._id} (${test.questions.length} questions)`);

  await mongoose.disconnect();
  console.log('Done.');
}

seed().catch(err => { console.error('Seed failed:', err); process.exit(1); });
